  Future<void> _handlePurchaseUpdates(List<PurchaseDetails> purchases) async {
    for (final p in purchases) {
      try {
        if (p.status == PurchaseStatus.pending) {
          _resultsController.add(PaymentResult(
            id: p.purchaseID ?? _randomId('iap_pending'),
            method: PaymentMethodType.inAppPurchase,
            status: PaymentStatus.pending,
            currency: config.defaultCurrency,
            amountMinor: 0,
            raw: _purchaseToRaw(p),
            message: 'Purchase pending',
          ));
          continue;
        }

        if (p.status == PurchaseStatus.error) {
          final msg = p.error?.message ?? 'Purchase failed';
          _resultsController.add(PaymentResult(
            id: p.purchaseID ?? _randomId('iap_error'),
            method: PaymentMethodType.inAppPurchase,
            status: PaymentStatus.failed,
            currency: config.defaultCurrency,
            amountMinor: 0,
            raw: _purchaseToRaw(p),
            message: msg,
          ));

          if (p.pendingCompletePurchase) {
            await _iap.completePurchase(p);
          }
          continue;
        }

        if (p.status == PurchaseStatus.canceled) {
          _resultsController.add(PaymentResult(
            id: p.purchaseID ?? _randomId('iap_canceled'),
            method: PaymentMethodType.inAppPurchase,
            status: PaymentStatus.canceled,
            currency: config.defaultCurrency,
            amountMinor: 0,
            raw: _purchaseToRaw(p),
            message: 'Purchase canceled',
          ));
          if (p.pendingCompletePurchase) {
            await _iap.completePurchase(p);
          }
          continue;
        }

        if (p.status == PurchaseStatus.purchased || p.status == PurchaseStatus.restored) {
          final purchaseId = p.purchaseID ?? _randomId('iap_noid');
          final verificationData = p.verificationData.serverVerificationData;
          final source = p.verificationData.source;

          final platform = defaultTargetPlatform == TargetPlatform.iOS ? 'ios' : 'android';

          final pending = _findPendingForPurchase(p);
          final amountMinor = pending?.expectedAmountMinor ?? 0;
          final currency = pending?.expectedCurrency ?? config.defaultCurrency;
          final metadata = pending?.metadata ?? const <String, dynamic>{};
          final idempotencyKey = pending?.idempotencyKey ?? _idempotencyKey('iap_verify', '$purchaseId:${DateTime.now().millisecondsSinceEpoch}');

          _assertNoCardDataInMetadata(metadata);

          final result = await gateway.verifyAndCaptureIap(
            platform: platform,
            productId: p.productID,
            purchaseId: purchaseId,
            verificationData: verificationData,
            source: source,
            idempotencyKey: idempotencyKey,
            metadata: metadata,
          );

          final enriched = result.copyWith(
            currency: result.currency.isNotEmpty ? result.currency : currency,
            amountMinor: result.amountMinor != 0 ? result.amountMinor : amountMinor,
            raw: {
              ...result.raw,
              'purchase': _purchaseToRaw(p),
            },
          );

          _resultsController.add(enriched);

          if (p.pendingCompletePurchase) {
            await _iap.completePurchase(p);
          }

          _cleanupPending(p);
        }
      } catch (e, st) {
        _resultsController.add(PaymentResult(
          id: p.purchaseID ?? _randomId('iap_exception'),
          method: PaymentMethodType.inAppPurchase,
          status: PaymentStatus.failed,
          currency: config.defaultCurrency,
          amountMinor: 0,
          raw: {'error': e.toString(), 'purchase': _purchaseToRaw(p)},
          message: 'Verification failed',
        ));

        if (p.pendingCompletePurchase) {
          try {
            await _iap.completePurchase(p);
          } catch (_) {}
        }

        if (kDebugMode) {
          // ignore: avoid_print
          print('IAP handling error: $e\n$st');
        }
      }
    }
  }

  _PendingIap? _findPendingForPurchase(PurchaseDetails p) {
    final purchaseId = p.purchaseID;
    if (purchaseId == null) return null;
    return _pendingIapByPurchaseId.values.firstWhere(
      (x) => x.maybeMatches(p),
      orElse: () => _PendingIap.empty(),
    ).isEmpty
        ? null
        : _pendingIapByPurchaseId.values.firstWhere((x) => x.maybeMatches(p));
  }

  void _cleanupPending(PurchaseDetails p) {
    final purchaseId = p.purchaseID;
    if (purchaseId == null) return;
    final keysToRemove = <String>[];
    _pendingIapByPurchaseId.forEach((k, v) {
      if (v.maybeMatches(p)) keysToRemove.add(k);
    });
    for (final k in keysToRemove) {
      _pendingIapByPurchaseId.remove(k);
    }
  }

  Map<String, dynamic> _purchaseToRaw(PurchaseDetails p) {
    return {
      'productID': p.productID,
      'purchaseID': p.purchaseID,
      'transactionDate': p.transactionDate,
      'status': p.status.name,
      'verificationData': {
        'source': p.verificationData.source,
        'localVerificationData': _redact(p.verificationData.localVerificationData),
        'serverVerificationData': _redact(p.verificationData.serverVerificationData),
      },
      'error': p.error == null
          ? null
          : {
              'code': p.error!.code,
              'message': p.error!.message,
              'details': '${p.error!.details}',
              'source': '${p.error!.source}',
            },
    };
  }

  void _assertNoCardDataInMetadata(Map<String, dynamic> metadata) {
    final banned = <String>[
      'card',
      'pan',
      'number',
      'cvc',
      'cvv',
      'expiry',
      'exp',
      'track',
      'magstripe',
      'pin',
      'iban',
    ];
    for (final entry in metadata.entries) {
      final k = entry.key.toLowerCase();
      if (banned.any((b) => k.contains(b))) {
        throw PaymentException('pci_violation', 'Metadata contains prohibited field: ${entry.key}');
      }
      final v = entry.value;
      if (v is String) {
        final lv = v.toLowerCase();
        if (lv.contains('4111') || lv.contains('4242')) {
          throw const PaymentException('pci_violation', 'Possible PAN detected in metadata');
        }
      }
    }
  }

  void _assertNoRawCardFields(Map<String, dynamic> payload) {
    final bannedKeys = <String>{
      'cardNumber',
      'number',
      'pan',
      'cvc',
      'cvv',
      'expiry',
      'expMonth',
      'expYear',
      'trackData',
      'pin',
    };
    bool hasBanned(Map<String, dynamic> map) {
      for (final e in map.entries) {
        if (bannedKeys.contains(e.key)) return true;
        final v = e.value;
        if (v is Map<String, dynamic> && hasBanned(v)) return true;
        if (v is List) {
          for (final it in v) {
            if (it is Map<String, dynamic> && hasBanned(it)) return true;
          }
        }
      }
      return false;
    }

    if (hasBanned(payload)) {
      throw const PaymentException('pci_violation', 'Do not pass raw cardholder data. Use a PCI-compliant SDK/tokenization.');
    }
  }

  static String _redact(String input) {
    if (input.isEmpty) return input;
    if (input.length <= 8) return '***';
    return '${input.substring(0, 4)}...${input.substring(input.length - 4)}';
  }
}

class _PendingIap {
  final String pendingId;
  final String productId;
  final int expectedAmountMinor;
  final String expectedCurrency;
  final bool isConsumable;
  final Map<String, dynamic> metadata;
  final String idempotencyKey;
  final DateTime startedAt;

  const _PendingIap({
    required this.pendingId,
    required this.productId,
    required this.expectedAmountMinor,
    required this.expectedCurrency,
    required this.isConsumable,
    required this.metadata,
    required this.idempotencyKey,
    required this.startedAt,
  });

  factory _PendingIap.empty() => _PendingIap(
        pendingId: '',
        productId: '',
        expectedAmountMinor: 0,
        expectedCurrency: '',
        isConsumable: false,
        metadata: const {},
        idempotencyKey: '',
        startedAt: DateTime.fromMillisecondsSinceEpoch(0),
      );

  bool get isEmpty => pendingId.isEmpty;

  bool maybeMatches(PurchaseDetails p) {
    if (p.productID != productId) return false;
    return true;
  }
}

class _StoreKitDelegate implements SKPaymentQueueDelegateWrapper {
  @override
  bool shouldContinueTransaction(SKPaymentTransactionWrapper transaction, SKStorefrontWrapper storefront) {
    return true;
  }

  @override
  bool shouldShowPriceConsent() {
    return false;
  }
}

String _randomId(String prefix) {
  final r = Random.secure();
  final bytes = List<int>.generate(12, (_) => r.nextInt(256));
  final s = base64UrlEncode(bytes).replaceAll('=', '');
  return '${prefix}_$s';
}

String _idempotencyKey(String prefix, String seed) {
  final data = utf8.encode('$prefix|$seed');
  final hash = _fnv1a64(data);
  return '${prefix}_${hash.toRadixString(16)}';
}

int _fnv1a64(List<int> bytes) {
  const int fnvPrime = 1099511628211;
  const int fnvOffset = 1469598103934665603;
  int hash = fnvOffset;
  for (final b in bytes) {
    hash ^= b;
    hash = (hash * fnvPrime) & 0x7fffffffffffffff;
  }
  return hash;
}

class MobileWalletBridge {
  static const MethodChannel _channel = MethodChannel('payment_module/wallet');

  static Future<String> requestApplePayToken({
    required String merchantIdentifier,
    required String countryCode,
    required String currencyCode,
    required int amountMinor,
    required String label,
    Map<String, dynamic> additional = const {},
  }) async {
    final res = await _channel.invokeMethod<String>('applePayToken', {
      'merchantIdentifier': merchantIdentifier,
      'countryCode': countryCode,
      'currencyCode': currencyCode,
      'amountMinor': amountMinor,
      'label': label,
      'additional': additional,
    });
    if (res == null || res.isEmpty) throw const PaymentException('wallet_no_token', 'No Apple Pay token received');
    return res;
  }

  static Future<String> requestGooglePayToken({
    required String merchantName,
    required String countryCode,
    required String currencyCode,
    required int amountMinor,
    required String label,
    Map<String, dynamic> additional = const {},
  }) async {
    final res = await _channel.invokeMethod<String>('googlePayToken', {
      'merchantName': merchantName,
      'countryCode': countryCode,
      'currencyCode': currencyCode,
      'amountMinor': amountMinor,
      'label': label,
      'additional': additional,
    });
    if (res == null || res.isEmpty) throw const PaymentException('wallet_no_token', 'No Google Pay token received');
    return res;
  }
}